1654	func updateGoGC(conf *config.Config, logger *slog.Logger) {
1655		oldGoGC := debug.SetGCPercent(conf.Runtime.GoGC)
1656		if oldGoGC != conf.Runtime.GoGC {
1657			logger.Info("updated GOGC", "old", oldGoGC, "new", conf.Runtime.GoGC)
1658		}
1659		// Write the new setting out to the ENV var for runtime API output.
1660		if conf.Runtime.GoGC >= 0 {
1661			os.Setenv("GOGC", strconv.Itoa(conf.Runtime.GoGC))
1662		} else {
1663			os.Setenv("GOGC", "off")
