// Package reload tracks and persists the outcome of the most recent
// configuration reload attempt so that it can be served over HTTP and
// survive process restarts. It is used by the opt-in transactional reload
// mode enabled with --enable-feature=transactional-reload-config.
package reload

import (
	"encoding/json"
	"errors"
	"log/slog"
	"os"
	"path/filepath"

	"github.com/prometheus/common/promslog"
)

// Error categories reported for a reload attempt. Exactly one of these is set
// on every recorded outcome.
const (
	// CategoryNone means no error occurred (or no reload has been attempted yet).
	CategoryNone = "none"
	// CategoryLoadError means the configuration file could not be loaded or parsed.
	// No reloader was applied and no rollback is attempted.
	CategoryLoadError = "load_error"
	// CategoryApplyError means at least one reloader failed while applying the new
	// configuration.
	CategoryApplyError = "apply_error"
	// CategoryRollbackError means a reloader failed and the subsequent rollback to
	// the last known-good configuration also failed, leaving a mixed runtime state.
	CategoryRollbackError = "rollback_error"
)

// StateFileName is the name of the file used to persist the most recent reload
// outcome under the configured TSDB storage directory.
const StateFileName = "reload_state.json"

// Outcome describes the result of a single configuration reload attempt. It is
// both the shape served at GET /api/v1/status/reload and the shape persisted to
// disk.
type Outcome struct {
	// LastReloadID is an RFC3339 timestamp identifying the attempt, or the empty
	// string if no reload has been attempted yet.
	LastReloadID string `json:"last_reload_id"`
	// LastReloadSuccessful reports whether the whole attempt succeeded.
	LastReloadSuccessful bool `json:"last_reload_successful"`
	// ErrorCategory is one of the Category* constants.
	ErrorCategory string `json:"error_category"`
	// ErrorMessage carries a human-readable description of the failure, if any.
	ErrorMessage string `json:"error_message"`
	// AppliedReloaders lists, in order, the reloaders that applied the new
	// configuration before the attempt completed or failed.
	AppliedReloaders []string `json:"applied_reloaders"`
	// RollbackAttempted reports whether a rollback to the last known-good
	// configuration was attempted.
	RollbackAttempted bool `json:"rollback_attempted"`
	// RollbackSuccessful reports whether that rollback succeeded.
	RollbackSuccessful bool `json:"rollback_successful"`
	// FailedReloader names the reloader that failed, if any.
	FailedReloader string `json:"failed_reloader"`
	// ReloaderTimings records how long each reloader took to run, in milliseconds.
	ReloaderTimings map[string]float64 `json:"reloader_timings_ms"`
}

// DefaultOutcome returns the outcome reported before any reload has been
// attempted.
func DefaultOutcome() Outcome {
	return Outcome{
		LastReloadID:         "",
		LastReloadSuccessful: false,
		ErrorCategory:        CategoryNone,
		AppliedReloaders:     []string{},
		ReloaderTimings:      map[string]float64{},
	}
}

// normalized fills in zero values so that JSON marshaling produces empty
// collections ([] and {}) rather than null, and a valid error category.
func (o Outcome) normalized() Outcome {
	if o.AppliedReloaders == nil {
		o.AppliedReloaders = []string{}
	}
	if o.ReloaderTimings == nil {
		o.ReloaderTimings = map[string]float64{}
	}
	if o.ErrorCategory == "" {
		o.ErrorCategory = CategoryNone
	}
	return o
}

// State holds the most recent reload outcome and persists it to disk. All
// methods are safe for concurrent use.
type State struct {
	path   string
	logger *slog.Logger

	outcome Outcome
	// outcome is accessed under this lock. A dedicated mutex keeps reads (the
	// HTTP endpoint) cheap and independent of disk writes.
	mtx chan struct{}
}

// NewState creates a State whose most recent outcome is persisted as JSON under
// dir (using StateFileName). If dir is empty, the outcome is kept in memory
// only. Any previously persisted outcome is loaded so that it survives
// restarts; a missing or corrupted file is tolerated and does not prevent
// startup — the State simply falls back to DefaultOutcome.
func NewState(dir string, logger *slog.Logger) *State {
	if logger == nil {
		logger = promslog.NewNopLogger()
	}
	s := &State{
		logger:  logger,
		outcome: DefaultOutcome(),
		mtx:     make(chan struct{}, 1),
	}
	s.mtx <- struct{}{}
	if dir == "" {
		return s
	}
	s.path = filepath.Join(dir, StateFileName)

	o, err := loadOutcome(s.path)
	switch {
	case err == nil:
		s.outcome = o.normalized()
	case errors.Is(err, os.ErrNotExist):
		// No prior state; keep the default. This is the expected case before
		// the first reload attempt.
	default:
		logger.Warn("Could not load persisted reload state; continuing with default", "path", s.path, "err", err)
	}
	return s
}

