// reloadTracker orchestrates transactional configuration reloads. It runs the
// reloaders in sequence, records a single outcome for the whole attempt, and,
// when a component fails after another has already applied the new
// configuration, attempts to roll every applied component back to the last
// known-good configuration.
//
// A tracker is used from a single goroutine at a time (the initial load
// completes and releases reloadReady before the reload loop starts), so
// lastGood needs no additional synchronization; the persisted state has its own
// locking.
type reloadTracker struct {
	state *reload.State
	// lastGood is the most recent configuration that every reloader applied
	// successfully, including the configuration loaded at startup. It is the
	// target of a rollback. It is nil until the first successful apply.
	lastGood *config.Config
}

// recordLoadError records an outcome for a failure to load or parse the
// configuration file. No component has been touched, so no rollback is
// attempted.
func (t *reloadTracker) recordLoadError(err error) {
	t.state.Set(reload.Outcome{
		LastReloadID:         time.Now().Format(time.RFC3339),
		LastReloadSuccessful: false,
		ErrorCategory:        reload.CategoryLoadError,
		ErrorMessage:         err.Error(),
	})
}

// apply runs the reloaders transactionally against conf and records the
// outcome. It returns a non-nil error if the attempt did not fully succeed.
func (t *reloadTracker) apply(conf *config.Config, filename string, logger *slog.Logger, rls []reloader) error {
	o := reload.Outcome{
		LastReloadID:     time.Now().Format(time.RFC3339),
		ErrorCategory:    reload.CategoryNone,
		AppliedReloaders: []string{},
		ReloaderTimings:  map[string]float64{},
	}

	for i, rl := range rls {
		rstart := time.Now()
		rerr := rl.reloader(conf)
		o.ReloaderTimings[rl.name] = float64(time.Since(rstart).Microseconds()) / 1000.0
		if rerr == nil {
			o.AppliedReloaders = append(o.AppliedReloaders, rl.name)
			continue
		}

		logger.Error("Failed to apply configuration", "reloader", rl.name, "err", rerr)
		o.LastReloadSuccessful = false
		o.ErrorCategory = reload.CategoryApplyError
		o.ErrorMessage = rerr.Error()
		o.FailedReloader = rl.name

		// Roll back only if a previous component already applied the new config
		// and we have a known-good config to restore.
		if i > 0 && t.lastGood != nil {
			o.RollbackAttempted = true
			if rbErr := rollbackReloaders(rls[:i], t.lastGood, logger); rbErr != nil {
				o.RollbackSuccessful = false
				o.ErrorCategory = reload.CategoryRollbackError
				o.ErrorMessage = fmt.Sprintf("apply error: %v; rollback error: %v", rerr, rbErr)
			} else {
				o.RollbackSuccessful = true
			}
		}

		t.state.Set(o)
		return fmt.Errorf("failed to apply new configuration for reloader %q (--config.file=%q): %w", rl.name, filename, rerr)
	}

	o.LastReloadSuccessful = true
	o.ErrorCategory = reload.CategoryNone
	t.lastGood = conf
	t.state.Set(o)
	return nil
}

// rollbackReloaders re-applies the last known-good configuration to every
// reloader that had already applied the new configuration, in order.
func rollbackReloaders(applied []reloader, good *config.Config, logger *slog.Logger) error {
	logger.Warn("Rolling back to last known-good configuration after a partial reload failure")
	var errs []error
	for _, rl := range applied {
		if err := rl.reloader(good); err != nil {
			logger.Error("Failed to roll back reloader to last known-good configuration", "reloader", rl.name, "err", err)
			errs = append(errs, fmt.Errorf("%s: %w", rl.name, err))
		}
	}
	return errors.Join(errs...)
}

