func TestDefaultOutcome(t *testing.T) {
	o := DefaultOutcome()
	require.Equal(t, "", o.LastReloadID)
	require.False(t, o.LastReloadSuccessful)
	require.Equal(t, CategoryNone, o.ErrorCategory)
	require.NotNil(t, o.AppliedReloaders)
	require.Empty(t, o.AppliedReloaders)
	require.NotNil(t, o.ReloaderTimings)
	require.Empty(t, o.ReloaderTimings)

	// The default outcome must marshal collections as [] and {}, not null.
	b, err := json.Marshal(o)
	require.NoError(t, err)
	require.Contains(t, string(b), `"applied_reloaders":[]`)
	require.Contains(t, string(b), `"reloader_timings_ms":{}`)
	require.Contains(t, string(b), `"error_category":"none"`)
}

func TestNewState_NoDir_NoFileWritten(t *testing.T) {
	s := NewState("", promslog.NewNopLogger())
	require.Equal(t, DefaultOutcome(), s.Outcome())
}

func TestNewState_MissingFile_NoFileWritten(t *testing.T) {
	dir := t.TempDir()
	s := NewState(dir, promslog.NewNopLogger())

	// Before any reload attempt, the default outcome is reported and no state
	// file is written.
	require.Equal(t, DefaultOutcome(), s.Outcome())
	_, err := os.Stat(filepath.Join(dir, StateFileName))
	require.True(t, os.IsNotExist(err), "no state file should exist before the first reload")
}

func TestState_SetPersistsAndReloads(t *testing.T) {
	dir := t.TempDir()
	s := NewState(dir, promslog.NewNopLogger())

	want := Outcome{
		LastReloadID:         "2026-07-14T10:00:00Z",
		LastReloadSuccessful: false,
		ErrorCategory:        CategoryApplyError,
		ErrorMessage:         "boom",
		AppliedReloaders:     []string{"a", "b"},
		RollbackAttempted:    true,
		RollbackSuccessful:   true,
		FailedReloader:       "c",
		ReloaderTimings:      map[string]float64{"a": 1, "b": 2, "c": 0.5},
	}
	s.Set(want)
	require.Equal(t, want, s.Outcome())

	// A fresh State over the same directory loads the persisted outcome,
	// simulating a restart.
	s2 := NewState(dir, promslog.NewNopLogger())
	require.Equal(t, want, s2.Outcome())
}

func TestNewState_CorruptedFile_FallsBackToDefault(t *testing.T) {
	dir := t.TempDir()
	require.NoError(t, os.WriteFile(filepath.Join(dir, StateFileName), []byte("{not json"), 0o644))

	s := NewState(dir, promslog.NewNopLogger())
	require.Equal(t, DefaultOutcome(), s.Outcome())
}

func TestState_SetNormalizesNilCollections(t *testing.T) {
	s := NewState("", promslog.NewNopLogger())
	s.Set(Outcome{LastReloadID: "id", ErrorCategory: ""})

	o := s.Outcome()
	require.Equal(t, CategoryNone, o.ErrorCategory)
	require.NotNil(t, o.AppliedReloaders)
	require.NotNil(t, o.ReloaderTimings)
}
