package main

import (
	"errors"
	"testing"

	"github.com/prometheus/common/promslog"
	"github.com/stretchr/testify/require"

	"github.com/prometheus/prometheus/config"
	"github.com/prometheus/prometheus/util/reload"
)

// applyRecorder builds a reloader that records the configs it is called with and
// optionally fails.
type applyRecorder struct {
	name  string
	calls []*config.Config
	fail  bool
}

func (r *applyRecorder) reloader() reloader {
	return reloader{
		name: r.name,
		reloader: func(c *config.Config) error {
			r.calls = append(r.calls, c)
			if r.fail {
				return errors.New(r.name + " failed")
			}
			return nil
		},
	}
}

func newTestTracker(t *testing.T) *reloadTracker {
	t.Helper()
	return &reloadTracker{state: reload.NewState(t.TempDir(), promslog.NewNopLogger())}
}

func TestTransactionalReload_Success(t *testing.T) {
	tr := newTestTracker(t)
	a := &applyRecorder{name: "a"}
	b := &applyRecorder{name: "b"}
	conf := &config.Config{}

	require.NoError(t, tr.apply(conf, "prometheus.yml", promslog.NewNopLogger(), []reloader{a.reloader(), b.reloader()}))

	o := tr.state.Outcome()
	require.True(t, o.LastReloadSuccessful)
	require.Equal(t, reload.CategoryNone, o.ErrorCategory)
	require.Equal(t, []string{"a", "b"}, o.AppliedReloaders)
	require.False(t, o.RollbackAttempted)
	require.Empty(t, o.FailedReloader)
	require.Contains(t, o.ReloaderTimings, "a")
	require.Contains(t, o.ReloaderTimings, "b")
	require.NotEmpty(t, o.LastReloadID)

	// The successful config becomes the last known-good config.
	require.Same(t, conf, tr.lastGood)
}

func TestTransactionalReload_LoadError_NoRollback(t *testing.T) {
	tr := newTestTracker(t)
	tr.lastGood = &config.Config{}

	tr.recordLoadError(errors.New("bad yaml"))

	o := tr.state.Outcome()
	require.False(t, o.LastReloadSuccessful)
	require.Equal(t, reload.CategoryLoadError, o.ErrorCategory)
	require.Equal(t, "bad yaml", o.ErrorMessage)
	require.False(t, o.RollbackAttempted)
	require.Empty(t, o.AppliedReloaders)
}

func TestTransactionalReload_FirstReloaderFails_NoRollback(t *testing.T) {
	tr := newTestTracker(t)
	// No previous good config and the very first reloader fails: nothing was
	// applied, so there is nothing to roll back.
	a := &applyRecorder{name: "a", fail: true}
	b := &applyRecorder{name: "b"}
	conf := &config.Config{}

	err := tr.apply(conf, "prometheus.yml", promslog.NewNopLogger(), []reloader{a.reloader(), b.reloader()})
	require.Error(t, err)

	o := tr.state.Outcome()
	require.False(t, o.LastReloadSuccessful)
	require.Equal(t, reload.CategoryApplyError, o.ErrorCategory)
	require.Equal(t, "a", o.FailedReloader)
	require.Empty(t, o.AppliedReloaders)
	require.False(t, o.RollbackAttempted)
	// The second reloader is never invoked once the first fails.
	require.Empty(t, b.calls)
}

func TestTransactionalReload_PartialFailure_RollsBack(t *testing.T) {
	tr := newTestTracker(t)
	good := &config.Config{}
	tr.lastGood = good // e.g. the startup config.

	a := &applyRecorder{name: "a"}
	b := &applyRecorder{name: "b"}
	c := &applyRecorder{name: "c", fail: true}
	d := &applyRecorder{name: "d"}
	newConf := &config.Config{}

	err := tr.apply(newConf, "prometheus.yml", promslog.NewNopLogger(), []reloader{a.reloader(), b.reloader(), c.reloader(), d.reloader()})
	require.Error(t, err)

	o := tr.state.Outcome()
	require.False(t, o.LastReloadSuccessful)
	require.Equal(t, reload.CategoryApplyError, o.ErrorCategory)
	require.Equal(t, "c", o.FailedReloader)
	require.Equal(t, []string{"a", "b"}, o.AppliedReloaders)
	require.True(t, o.RollbackAttempted)
	require.True(t, o.RollbackSuccessful)

	// a and b are re-applied with the known-good config; d is never touched.
	require.Equal(t, []*config.Config{newConf, good}, a.calls)
	require.Equal(t, []*config.Config{newConf, good}, b.calls)
	require.Equal(t, []*config.Config{newConf}, c.calls)
	require.Empty(t, d.calls)

