package main

import (
	"errors"
	"testing"

	"github.com/prometheus/common/promslog"
	"github.com/stretchr/testify/require"

	"github.com/prometheus/prometheus/config"
	"github.com/prometheus/prometheus/util/reload"
)

// applyRecorder builds a reloader that records the configs it is called with and
// optionally fails.
type applyRecorder struct {
	name  string
	calls []*config.Config
	fail  bool
}

func (r *applyRecorder) reloader() reloader {
	return reloader{
		name: r.name,
		reloader: func(c *config.Config) error {
			r.calls = append(r.calls, c)
			if r.fail {
				return errors.New(r.name + " failed")
			}
			return nil
		},
	}
}

func newTestTracker(t *testing.T) *reloadTracker {
	t.Helper()
	return &reloadTracker{state: reload.NewState(t.TempDir(), promslog.NewNopLogger())}
}

func TestTransactionalReload_Success(t *testing.T) {
	tr := newTestTracker(t)
	a := &applyRecorder{name: "a"}
	b := &applyRecorder{name: "b"}
	conf := &config.Config{}

	require.NoError(t, tr.apply(conf, "prometheus.yml", promslog.NewNopLogger(), []reloader{a.reloader(), b.reloader()}))

	o := tr.state.Outcome()
	require.True(t, o.LastReloadSuccessful)
	require.Equal(t, reload.CategoryNone, o.ErrorCategory)
	require.Equal(t, []string{"a", "b"}, o.AppliedReloaders)
	require.False(t, o.RollbackAttempted)
	require.Empty(t, o.FailedReloader)
	require.Contains(t, o.ReloaderTimings, "a")
	require.Contains(t, o.ReloaderTimings, "b")
	require.NotEmpty(t, o.LastReloadID)

	// The successful config becomes the last known-good config.
	require.Same(t, conf, tr.lastGood)
}

func TestTransactionalReload_LoadError_NoRollback(t *testing.T) {
	tr := newTestTracker(t)
	tr.lastGood = &config.Config{}

	tr.recordLoadError(errors.New("bad yaml"))

	o := tr.state.Outcome()
	require.False(t, o.LastReloadSuccessful)
	require.Equal(t, reload.CategoryLoadError, o.ErrorCategory)
	require.Equal(t, "bad yaml", o.ErrorMessage)
	require.False(t, o.RollbackAttempted)
	require.Empty(t, o.AppliedReloaders)
}

