	o := tr.state.Outcome()
	require.False(t, o.LastReloadSuccessful)
	require.Equal(t, reload.CategoryApplyError, o.ErrorCategory)
	require.Equal(t, "c", o.FailedReloader)
	require.Equal(t, []string{"a", "b"}, o.AppliedReloaders)
	require.True(t, o.RollbackAttempted)
	require.True(t, o.RollbackSuccessful)

	// a and b are re-applied with the known-good config; d is never touched.
	require.Equal(t, []*config.Config{newConf, good}, a.calls)
	require.Equal(t, []*config.Config{newConf, good}, b.calls)
	require.Equal(t, []*config.Config{newConf}, c.calls)
	require.Empty(t, d.calls)

	// A failed reload does not update the last known-good config.
	require.Same(t, good, tr.lastGood)
}

